window.__QUIZ_DATA__=[{"id":"theory>Physics>2013>1","subject":"Physics","year":"2013","type":"Theory","sub_label":"1","group":"","topic":"PROJECTILE MOTION :","question":"A projectile is released with a speed u at an angle \u03b8 to the horizontal. With the aid of a diagram, show that the time of flight is equal to 2uSin\u03b8/q, where g is the acceleration of free fall.","images":["data:image/png;base64,"],"marking_scheme":"Vertical (component of) velocity = u sin \u03b8     if time taken to reach a height is t then,    v= u sin \u03b8  - gt    t = u sin \u03b8 /g    but the projectile takes the same time to do the rest of the flight (i.e trajectory is symmetrical)    therefore Time of flight, T = 2t = 2usin \u03b8/g","marks":"3","difficulty":"3"},{"id":"theory>Physics>2013>2>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"FINAL","topic":"PROJECTILE MOTION :","question":"The horizontal component of the initial speed of a particle projected at 30o to the horizontal is 50ms-1. If the acceleration of free fall due to gravity is 10ms-2. Determine its initial speed","images":[],"marking_scheme":"Parameters given:\u03b8 = 30o, Vx = 50ms-1, g = 10ms-1, u = ?   Recall that::   Vx = Ucos\u03b8   \u2234 U = Ux/cos\u03b8 = 50/cos30 = 50/0.8660    Initial speed = 57.74ms-1.","marks":"1.5","difficulty":"2"},{"id":"theory>Physics>2013>2>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"FINAL","topic":"PROJECTILE MOTION :","question":"The horizontal component of the initial speed of a particle projected at 30o to the horizontal is 50ms-1. If the acceleration of free fall due to gravity is 10ms-2. Determine its speed at the maximum height reached","images":[],"marking_scheme":"Let v represent its velocity at the maximum height. At the maximum height    Vy = 0    Vx =Ux = 50ms-1","marks":"1","difficulty":"2"},{"id":"theory>Physics>2013>3","subject":"Physics","year":"2013","type":"Theory","sub_label":"3","group":"FINAL","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"In an electrolysis experiment, the ammeter records a steady current of 1A. The mass of copper deposited in 30minutes is 0.66g. Calculate the error in the ammeter reading.   [Electrochemical equivalent of copper = 0.00033gC-1]","images":[],"marking_scheme":"Parameters given:Current, I = 1A,Mass, M = 0.66g,Time, t = 30 x 60 = 18000seconds    z = 0.00033g^c-1, error = ?, m = ZIt,    I = m/Zt    I=0.660.00033 x 1800 = 0.66/0.594    I = 1.11A    Error = 1.11 - 1.0 = 0.11A","marks":"1","difficulty":"3"},{"id":"theory>Physics>2013>4>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"What is Brownian motion?","images":[],"marking_scheme":"This is continuous random movement of particles suspended in a fluid","marks":"1","difficulty":"1"},{"id":"theory>Physics>2013>4>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"State the two inferences that can be drawn from Brownian motion experiment.","images":[],"marking_scheme":"- existence of molecules, (proving the molecular theory of matter)  - motion of molecules, (proving kinetics theory of matter)","marks":"2","difficulty":"1"},{"id":"theory>Physics>2013>5","subject":"Physics","year":"2013","type":"Theory","sub_label":"5","group":"","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"A mass of 11.0kg is suspended from a rigid support by an aluminium wire of length 2.0m, diameter 2.0mm and Young's modulus 7.0 x 1011 Nm-2. Determine the extension produced. [g = 10ms-1, \u03c0 = 3.142]","images":[],"marking_scheme":"E = Fl/Ae = 110\u00d72.0/ 7.0\u00d7 1011 \u00d7( 3.142 \u00d7 (2.0/1000)2 / 4 ) = 1.0 \u00d7 10-4 m or 0.10mm","marks":"1","difficulty":"3"},{"id":"theory>Physics>2013>6>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"What is a polarizer?","images":[],"marking_scheme":"Polarizer is an optical device which allows vibration of light to pass through in only one plane perpendicular to the direction of propagation","marks":"1","difficulty":"1"},{"id":"theory>Physics>2013>6>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"With the aid of a diagram, explain how a polarizer can be used to polarize a beam of unpolarized light.","images":["data:image/png;base64,"],"marking_scheme":"Unpolarized light has vibrations in all direction. A polarized blocks all other vibrations and transmits vibrations in only one plane perpendicular to the direction of propagation.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2013>7>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTRODUCTION TO LASER :","question":"Name one use of 'LASER' in each of the following areas;   (a) communication   (b) medicine    (c) security","images":[],"marking_scheme":"Communication   - for hologram production, CD, DVD playing, VCD, space communication, data transfer, fiber-optic cable.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2013>7>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"","topic":"INTRODUCTION TO LASER :","question":"Name one use of 'LASER' in this area: medicine","images":[],"marking_scheme":"Medicine   - welding the retina of our eyes, boring holes in the skull, cervical cancer surgery, dentistry, cauterizing blood vessels, testing biological samples, monitoring glucose level of diabetic patient.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2013>7>c","subject":"Physics","year":"2013","type":"Theory","sub_label":"c","group":"","topic":"INTRODUCTION TO LASER :","question":"Name one use of 'LASER' in this area:Security","images":[],"marking_scheme":"Security   - guidance system of missiles, aircrafts and satelites, generation of isotopes for nuclear weapons/reactors/enriched uranium production","marks":"1","difficulty":"1"},{"id":"theory>Physics>2013>8","subject":"Physics","year":"2013","type":"Theory","sub_label":"8","group":"","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The accelerating potential in a cathode ray oscilloscope is 2.5kV. Calculate the maximum speed of the acceleration electrons.  [e = 1.6 x 10-19C, me = 9.1 x 10-3kg]","images":[],"marking_scheme":"1/2 me v2 = eV    v2 = 2eV/me = (2 \u00d7 1.6 \u00d7 10-19 \u00d7 2500)/(9.1\u00d7 10-31) = 8.79 \u00d7 1014    v= 2.965 \u00d7 107 ms-1","marks":"3","difficulty":"3"},{"id":"theory>Physics>2013>9","subject":"Physics","year":"2013","type":"Theory","sub_label":"9","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"Name the three basic components P, Q and R that make up a cathode ray tube, as illustrated in the diagram above.","images":["data:image/png;base64,"],"marking_scheme":"P is electron gun  Q is deflector plates  R is glass envelope","marks":"3","difficulty":"2"},{"id":"theory>Physics>2013>10>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Write down the name of two particles used in explaining the wave nature of matter.","images":[],"marking_scheme":"- Electrons  - Neutrons  - Hydrogen atom/proton  - Helium nuclei/alpha particles","marks":"2","difficulty":"2"},{"id":"theory>Physics>2013>10>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Write down the name of one device whose invention is based on the wave nature of matter.","images":[],"marking_scheme":"- Electron microscope  - Scanning tunneling microscope (STM)","marks":"1","difficulty":"2"},{"id":"theory>Physics>2013>11>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"SCALARS AND VECTORS : ADDITION OF VECTORS","question":"State the Triangle law of vector addition","images":[],"marking_scheme":"Triangle-law of vector addition states that if three forces are in equilibrium they can be represented in both magnitude and direction by the three sides of a triangle taken in order.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2013>11>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION","question":"Name the four physical quantities that are associated with the equations of linear motion.","images":[],"marking_scheme":"- Velocity  - Acceleration  - Time  - Speed","marks":"2","difficulty":"1"},{"id":"theory>Physics>2013>11>c","subject":"Physics","year":"2013","type":"Theory","sub_label":"c","group":"","topic":"SIMPLE HARMONIC MOTION : ENERGY OF S.H.M","question":"Using the same set of axes, sketch and label two graphs to illustrate the variation of potential energy and kinetic energy with time for a body in simple harmonic motion.","images":["Physics/imgs/2013/2013 2.png"],"marking_scheme":"* At A, the Potential Energy (P.E) of the body is maximum and K.E = 0   * A B, the Kinetic Energy (K.E) of the body is maximum and P.E = 0  * Time at B is less than time at c.   * So it can be deduced that, as a be the time increases, the potential energy increases and the kinetic energy decrease.","marks":"3","difficulty":"3"},{"id":"theory>Physics>2013>11>d>i","subject":"Physics","year":"2013","type":"Theory","sub_label":"i","group":"FINAL","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"A light spiral of force constant k lies on a horizontal frictionless surface and has one end fixed to a vertical wall. A block P of mass 2.0kg placed against the free end of the spring is pushed a distance 5cm towards the wall with 10J of energy as illustrated in the diagram above. The block is released and after 0.25s, it collides inelastically with a stationary block Q of mass 4.0kg.    Calculated the value of k.","images":["data:image/png;base64,"],"marking_scheme":"W = 1/2 ke2  10 = 1/2 \u00d7 k \u00d7 (5/100)2  k = 8000Nm","marks":"2","difficulty":"3"},{"id":"theory>Physics>2013>11>d>ii","subject":"Physics","year":"2013","type":"Theory","sub_label":"ii","group":"FINAL","topic":"WORK, ENERGY AND POWER : APPLICATION OF MECHANICAL ENERGY","question":"A light spiral of force constant k lies on a horizontal frictionless surface and has one end fixed to a vertical wall. A block P of mass 2.0kg placed against the free end of the spring is pushed a distance 5cm towards the wall with 10J of energy as illustrated in the diagram above. The block is released and after 0.25s, it collides inelastically with a stationary block Q of mass 4.0kg.    Calculated the force used to compress the spring.","images":["data:image/png;base64,"],"marking_scheme":"F = ke = 8000 \u00d7 (5/100) = 400N","marks":"2","difficulty":"3"},{"id":"theory>Physics>2013>11>d>iii","subject":"Physics","year":"2013","type":"Theory","sub_label":"iii","group":"FINAL","topic":"WORK, ENERGY AND POWER : APPLICATION OF MECHANICAL ENERGY","question":"A light spiral of force constant k lies on a horizontal frictionless surface and has one end fixed to a vertical wall. A block P of mass 2.0kg placed against the free end of the spring is pushed a distance 5cm towards the wall with 10J of energy as illustrated in the diagram above. The block is released and after 0.25s, it collides inelastically with a stationary block Q of mass 4.0kg.    Calculated the acceleration of the block p after release.","images":["data:image/png;base64,"],"marking_scheme":"F = ma    400 = 2.0 \u00d7 a     a = 200ms-2","marks":"1","difficulty":"3"},{"id":"theory>Physics>2013>11>d>iv","subject":"Physics","year":"2013","type":"Theory","sub_label":"iv","group":"FINAL","topic":"WORK, ENERGY AND POWER : APPLICATION OF MECHANICAL ENERGY","question":"A light spiral of force constant k lies on a horizontal frictionless surface and has one end fixed to a vertical wall. A block P of mass 2.0kg placed against the free end of the spring is pushed a distance 5cm towards the wall with 10J of energy as illustrated in the diagram above. The block is released and after 0.25s, it collides inelastically with a stationary block Q of mass 4.0kg.    Calculated the common speed after collision of the blocks.","images":["data:image/png;base64,"],"marking_scheme":"Initial velocity of block P = Up = 200 \u00d7 0.25 = 50 ms-1    Mp Up + MQ UQ  = (MP + MQ)v     Where v is the common velocity after collision    (2 \u00d7 50) + ( 4.0 \u00d7 0) = (2+4) v  100 = 6v  v = 16.7ms-1","marks":"3","difficulty":"3"},{"id":"theory>Physics>2013>12>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HEAT ENERGY : BOILING POINT","question":"Define boiling point of a liquid","images":[],"marking_scheme":"Boiling point of a liquid is that temperature at which its saturated vapour pressure is equal to the atmospheric pressure or the external pressure.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2013>12>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"HEAT ENERGY : BOILING POINT","question":"Describe how water in a round bottom flask could be made to boil without heating it.","images":[],"marking_scheme":"A round bottom flask not fully/partially filled with water is connected to a vacuum pump, Air is gradually pumped out of the flask until s.v.p = atmospheric pressure, At this stage the water is observed to be boiling.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2013>12>c","subject":"Physics","year":"2013","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"State three applications of expansion of metals","images":[],"marking_scheme":"Metal expansion is applied in the under-listed case studies   - Thermostat  - Riveting two or more metal plates  - Automatic fire alarms   - Fixing of metal rims on metal wheels  - fusing of platinum wire through walls of glass vessels  - construction of bridges or railway lines","marks":"3","difficulty":"1"},{"id":"theory>Physics>2013>12>d>i","subject":"Physics","year":"2013","type":"Theory","sub_label":"i","group":"FINAL","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A room with floor measurements 7m x 10m contains air of mass 250kg at a temperature of 34oC. The air is cooled until temperature falls to 24oC. Calculate the height of the room    [Specific heat capacity of air = 1010Jkg-1K-1, density of air = 1.25 kgm-3]","images":[],"marking_scheme":"Parameters given: Volume of air = volume of the room   Volume of air = mass of air/density = 250/1.25 = 200m3   \u2234 Volume of the room = 200m3 = L x B x H    L = 10m, B = 7m, H = ?   \u2234 H = volume/L x B    = 200/10 x 7    = 2.86m","marks":"2","difficulty":"3"},{"id":"theory>Physics>2013>12>d>ii","subject":"Physics","year":"2013","type":"Theory","sub_label":"ii","group":"FINAL","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A room with floor measurements 7m x 10m contains air of mass 250kg at a temperature of 34oC. The air is cooled until temperature falls to 24oC. Calculate the quantity of energy extracted to cool the room  [Specific heat capacity of air = 1010Jkg-1K-1, density of air = 1.25 kgm-3]","images":[],"marking_scheme":"Q = mc \u2206\u03b8  = 250 \u00d7 1010 \u00d7 (34 - 24)  2525000 = 2.525 \u00d7 106 J","marks":"2","difficulty":"3"},{"id":"theory>Physics>2013>12>d>iii","subject":"Physics","year":"2013","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A room with floor measurements 7m x 10m contains air of mass 250kg at a temperature of 34oC. The air is cooled until temperature falls to 24oC. Calculate the ** which is higher, the calculated value or the actual energy needed to cool the room? Give a reason for your answer.    [Specific heat capacity of air = 1010Jkg-1K-1, density of air = 1.25 kgm-3]","images":[],"marking_scheme":"- Part of heat is extracted from other materials/walls in the room  - Room is not air tight; hence heat leakages in and out of the room need to be compensated for.","marks":"1","difficulty":"3"},{"id":"theory>Physics>2013>13>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"SOUND WAVES : SPEED OF SOUND","question":"On which day would sound wave travels faster; on a hot or cold day? Explain","images":[],"marking_scheme":"Speed of sound is proportional to the square root of absolute temperature, v \u03b1 \u221aT. Hence the higher the temperature the greater the speed of sound.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2013>13>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"SOUND WAVES : TRANSMISSION OF SOUND WAVES","question":"Why are megaphones shaped like funnels?","images":[],"marking_scheme":"Intensity of sound is energy per seconds per unit area. Hence sound produced has greater intensity before spreading out through the larger segment of the cone.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2013>13>c>i","subject":"Physics","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A ray of light is incident on a surface of a rectangular glass prism of refractive index 1.5 as illustrated in the diagram below.     (i) Copy the diagram and label the angles of: (\u03b1) Incident (x); (\u03b2) reflection (y); (\u03b3) refraction (z), with the letters indicated.","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Physics>2013>13>c>ii","subject":"Physics","year":"2013","type":"Theory","sub_label":"ii","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A ray of light is incident on a surface of a rectangular glass prism of refractive index 1.5 as illustrated in the diagram below.       Calculate the angle of refraction to the nearest whole number.","images":["data:image/png;base64,"],"marking_scheme":"n =sini/sinr    1.5 = sin 60/sinr    r = sin-1 0.5774     r = 35o","marks":"3","difficulty":"3"},{"id":"theory>Physics>2013>13>d","subject":"Physics","year":"2013","type":"Theory","sub_label":"d","group":"FINAL","topic":"SIMPLE HARMONIC MOTION : FREQUENCY OF S.H.M","question":"A sonometer wire vibrates in simple harmonic motion with a maximum amplitude of 1.0cm. calculate the frequency of vibration of the wire, given that the magnitude of the maximum acceleration of the wire is 988ms-2.   [\u03c0 = 22/7]","images":[],"marking_scheme":"a = \u03c9 2 r; \u03c9 = 2\u220f f    a = (2 \u03c0f)2 r    988 = (2 \u00d7 22/7 \u00d7 f)2 \u00d7 1.0/100    f=50.0Hz","marks":"3","difficulty":"3"},{"id":"theory>Physics>2013>14>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Explain briefly the purpose of earthing an electrical appliance.","images":[],"marking_scheme":"The ground wire is a safety device   In the event of a short circuit occurring in the appliance the dangerous current, instead of passing through our body when we touch the appliances, gets sent safety to the earth (ground) through the grounding wire because the ground has much lower resistance than our body does.","marks":"3","difficulty":"1"},{"id":"theory>Physics>2013>14>b","subject":"Physics","year":"2013","type":"Theory","sub_label":"b","group":"","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Why does the light form a bulb connected to a simple cell dim and eventually goes off after a while?","images":[],"marking_scheme":"Because they have two basic defects namely  - polarization  - local action","marks":"2","difficulty":"1"},{"id":"theory>Physics>2013>14>c>i","subject":"Physics","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"SIMPLE A.C. CIRCUITS : VECTOR DIAGRAMS","question":"A coil of indicating 0.007H, a resistor of resistance 8\u03a9 and a capacitor of capacitance 0.001F are connected in series to an a.c source of frequency 500/\u03c0Hz. If the r.m.s voltages across the coil, the resistor and the capacitor are 30V, 30V and 70V respectively.   draw a vector diagram to illustrate the voltage across the components in the circuit.","images":["data:image/png;base64,"],"marking_scheme":"Frequency of the secondary output = 50Hz     (\u03b1)   V2 rms = V2R + ( Vc - VL )2   V2 rms = 302 +(70-30)2  V2 rms =(900 +1600) = 2500  V2 rms  = 50V","marks":"4","difficulty":"3"},{"id":"theory>Physics>2013>14>c>ii","subject":"Physics","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"A coil of indicating 0.007H, a resistor of resistance 8\u03a9 and a capacitor of capacitance 0.001F are connected in series to an a.c source of frequency 500/\u03c0Hz. If the r.m.s voltages across the coil, the resistor and the capacitor are 30V, 30V and 70V respectively    calculate the r.m.s voltage of the source   (\u03b2) r.m.s current in the circuit   (\u03b3) power dissipated in the circuit.","images":["data:image/png;base64,"],"marking_scheme":"Recall that: V2 = V2R + (VL - VC)   From the parameters given:V2 = 302 + (30 - 70)2   V2 = 900 + (-40)2    V2 = 900 + 1600   V2 = 2500   V = &radic;2500&nbsp;   Vr.m.s = 50V    For inductor, XL = 2\u03c0FL    = 2 x \u03c0 x 500/\u03c0 x 0.007    = 1000 x 0.007 = 7\u03a9   Capacitance reactance, Xc = 1/wc = 1/2\u03c0fc    Xc=12 x \u03c0 x 500/\u03c0 x 0.001    Xc = 1/2 x 500 x 0.001    = 1/1   \u2234 Xc = 1\u03a9,    Z = &radic;R2 + (XL - XC)2&nbsp;    = &radic;82 + (7 - 1)2&nbsp; = &radic;64 + 62&nbsp; = &radic;64 + 36&nbsp;    = &radic;100&nbsp;    Z = 10\u03a9   \u03b2, V = IZ;   1r.m.s = Vr.m.s/Z = 50/10    1 r.m.s = 5A   \u03b3, P = I2R = 52 x 8 = 25 x 8 = 200w","marks":"4","difficulty":"3"},{"id":"theory>Physics>2013>14>c>iii","subject":"Physics","year":"2013","type":"Theory","sub_label":"iii","group":"","topic":"SIMPLE A.C. CIRCUITS : GRAPHICAL REPRESENTATION OF E.M.F AND CURRENT IN AN A.C. CIRCULT","question":"A coil of indicating 0.007H, a resistor of resistance 8\u03a9 and a capacitor of capacitance 0.001F are connected in series to an a.c source of frequency 500/\u03c0Hz. If the r.m.s voltages across the coil, the resistor and the capacitor are 30V, 30V and 70V respectively  write down the sinusoidal equation for the r.m.s voltage, V, in terms of the time, t.","images":[],"marking_scheme":"V 0 = V rms \u221a2 = 50 \u00d7 \u221a2 = 70.7V    2\u03c0 ft= 2\u00d7\u03c0x 500/\u03c0 xt = 1000t    V = V0 Sin 2\u03c0 ft  V = 70.7 sin 1000t","marks":"2","difficulty":"3"},{"id":"theory>Physics>2013>15>a","subject":"Physics","year":"2013","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Define ionization potential","images":[],"marking_scheme":"Ionization potential can be explained as the energy needed to remove completely an electron from an atom.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2013>15>b>i","subject":"Physics","year":"2013","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"State the three types of emission spectra","images":[],"marking_scheme":"Continuous spectra, Line spectra, Band spectra","marks":"3","difficulty":"1"},{"id":"theory>Physics>2013>15>b>ii","subject":"Physics","year":"2013","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Name one source each which produces each of the spectra stated in 15(b)(i)","images":[],"marking_scheme":"Continuous spectra from sun/ solids / liquids.   Line spectra from atoms in gases e.g Hydrogen / neon ( at low pressure in a discharge tube)   Band spectra from molecules/ carbon (iv) oxide(in a discharge tube).","marks":"3","difficulty":"1"},{"id":"theory>Physics>2013>15>c>i","subject":"Physics","year":"2013","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"In an x-ray tube, electrons are accelerated to the target by a potential difference of 80kV. Calculate the speed of the electron   [h = 6.6 x 10-34Js, e = 1.6 x 10-19C, Me = 9.1 x 10-31kg]","images":[],"marking_scheme":"1eV = 1/2 mv2  1.6 \u00d7 10-19 \u00d7 80 \u00d7 103 =  1/2 \u00d7 9.1 \u00d7 10-31 \u00d7 v2  v2 = 2.81 \u00d7 1016  v = 1.68 \u00d7 108 ms-1","marks":"1","difficulty":"3"},{"id":"theory>Physics>2013>15>c>ii","subject":"Physics","year":"2013","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"In an x-ray tube, electrons are accelerated to the target by a potential difference of 80kV. Calculate the threshold wave length of the electron.  [h = 6.6 x 10-34Js, e = 1.6 x 10-19C, Me = 9.1 x 10-31kg]","images":[],"marking_scheme":"\u03bb = \u03bb/mv = 6.6 \u00d7 10-34 / 9.1 \u00d710-31 \u00d7 1.68\u00d7 108    4.32 \u00d7 10-12 m","marks":"2","difficulty":"3"},{"id":"theory>Physics>2013>15>d","subject":"Physics","year":"2013","type":"Theory","sub_label":"d","group":"","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"An x-ray photon of frequency 4.5 x 1018Hz strikes an electron, assumed to be at rest. If the electron absorbs all the photon energy, calculate the speed acquired by the electron.   [h = 6.6 x 10-34, Me = 9.1 x 10-31kg]","images":[],"marking_scheme":"Parameters given: Frequency, F = 4.5 x 1018Hz,planck constant, h = 6.6 x 10-34, Mass of electron,Me = 9.1 x 1031kg   E = hf = 1/2mr2    V2 = 2hf/m    v2=2 x 6.6 x 10-34 x 4.5 x 10189.1 x 10-31    = 65.27 x 1014    V = &radic;65.27 x 1014&nbsp;    = 8.08 x 107ms-1","marks":"2","difficulty":"3"}];